pnlCanvas.setKeyPressCallback(function(event)
{
	switch (event.keyCode)
	{
		case 97: // a
			player.angle -= 0.1;
			break;

		case 100: // d
			player.angle += 0.1;			
			break;

		case 115: // s
			player.x -= player.deltaX;
			player.y -= player.deltaY;
			break;

		case 119: // w
			player.x += player.deltaX;
			player.y += player.deltaY;
			break;
	}

	if (player.angle < 0)
		player.angle += 2 * Math.PI;
	else if (player.angle > 2 * Math.PI)
		player.angle -= 2 * Math.PI;

	player.deltaX = Math.cos(player.angle) * 5;
	player.deltaY = Math.sin(player.angle) * 5;
});

//! Functions
inline function init()
{
	player.x = 195;
	player.y = 195;
	player.deltaX = Math.cos(player.angle) * 5;
	player.deltaY = Math.sin(player.angle) * 5;

	pnlCanvas.repaint();
}

inline function drawPlayer()
{
	g.setColour(this.get("itemColour"));
	g.fillRect([player.x, player.y, player.width, player.height]);

	g.drawLine(player.x + player.width / 2, player.x + player.deltaX * 5 + player.width / 2, player.y + player.height / 2, player.y + player.deltaY * 5 + player.height / 2, 2);
}

inline function drawMap()
{
	for (i = 0; i < map.length; i++)
	{
		for (j = 0; j < map[i].length; j++)
		{
			if (map[i][j] == 0)
				g.setColour(Colours.black);
			else
				g.setColour(Colours.white);

			local area = Rectangle(i * world.size, j * world.size, world.size, world.size);

			g.fillRect(area.reduced(1));
		}
	}
}

inline function drawRays()
{
	local numRays = 60;

	local ray = {
		x: 0,
		y: 0,
		xOffset: 0,
		yOffset: 0,
		angle: player.angle - DR * 30,
		distanceH: 100000000000,
		distanceV: 100000000000,
		distance: 0,
		verticalX: 0,
		verticalY: 0,
		horizontalX: 0,
		horizontalY: 0,
	};

	if (ray.angle < 0)
		ray.angle += 2 * Math.PI;

	if (ray.angle > 2 * Math.PI)
		ray.angle -= 2 * Math.PI; 

	for (i = 0; i < numRays; i++)
	{
		horizontalLineCheck(ray);
		verticalLineCheck(ray);

		if (ray.distanceV < ray.distanceH)
		{
			ray.x = ray.verticalX;
			ray.y = ray.verticalY;
			ray.distance = ray.distanceV;
		}

		if (ray.distanceH < ray.distanceV)
		{
			ray.x = ray.horizontalX;
			ray.y = ray.horizontalY;
			ray.distance = ray.distanceH;
		}

		g.setColour(this.get("itemColour2"));
		g.drawLine(player.x + player.width / 2, player.width / 2 + ray.x, player.y + player.height / 2, player.height / 2 + ray.y, 2);

		draw3D(i, ray);

		ray.angle += DR;

		if (ray.angle < 0)
			ray.angle += 2 * Math.PI;

		if (ray.angle > 2 * Math.PI)
			ray.angle -= 2 * Math.PI; 
	}	
}

inline function draw3D(index: number, ray: object)
{
	local correctionAngle = player.angle - ray.angle;

	if (correctionAngle < 0)
		correctionAngle += 2 * Math.PI;

	if (correctionAngle > 2 * Math.PI)
		correctionAngle -= 2 * Math.PI;		

	ray.distance = ray.distance * Math.cos(correctionAngle); // Fix fisheye

	local viewWidth = 320;
	local lineHeight = Math.min(viewWidth, world.size * viewWidth / ray.distance);
	local lineOffset = 160 - lineHeight / 2;
	local startX = world.width * world.size;

	g.setColour(Colours.withMultipliedBrightness(Colours.red, ray.x == ray.verticalX ? 0.2 : 1.0));
	g.drawLine(index * 8 + startX, index * 8 + startX, lineOffset, lineHeight + lineOffset, 10);
}

inline function horizontalLineCheck(ray: object)
{
	local depthOfField = 0;	
	local aTan = -1 / Math.tan(ray.angle);

	if (ray.angle > Math.PI) // Looking up
	{
		ray.y = Math.round(player.y / world.size) * world.size - 0.0001;
		ray.x = (player.y - ray.y) * aTan + player.x;
		ray.yOffset =- world.size;
		ray.xOffset =- ray.yOffset * aTan;
	}

	if (ray.angle < Math.PI) // Looking down
	{
		ray.y = Math.round(player.y / world.size) * world.size + world.size;
		ray.x = (player.y - ray.y) * aTan + player.x;
		ray.yOffset = world.size;
		ray.xOffset =- ray.yOffset * aTan;
	}

	if (ray.angle == 0 || ray.angle == Math.PI) // Straight left or right
	{
		ray.x = player.x;
		ray.y = player.y;
		depthOfField = 8;
	}

	while (depthOfField < 8)
	{		
		local mapX = ray.x / world.size;
		local mapY = ray.y / world.size;

		if (isDefined(map[mapX][mapY]) && map[mapX][mapY] == 1)
		{
			depthOfField = 8;
			ray.horizontalX = ray.x;
			ray.horizontalY = ray.y;
			ray.distanceH = getDistance(player.x, player.y, ray.x, ray.y);
		}				
		else
		{
			ray.x += ray.xOffset;
			ray.y += ray.yOffset;
			depthOfField++;
		}
	}
}

inline function verticalLineCheck(ray: object)
{
	local depthOfField = 0;	
	local nTan = -Math.tan(ray.angle);

	if (ray.angle > PI2 && ray.angle < PI3) // Looking left
	{
		ray.x = Math.round(player.x / world.size) * world.size - 0.0001;
		ray.y = (player.x - ray.x) * nTan + player.y;
		ray.xOffset =- world.size;
		ray.yOffset =- ray.xOffset * nTan;
	}

	if (ray.angle < PI2 || ray.angle > PI3) // Looking right
	{
		ray.x = Math.round(player.x / world.size) * world.size + world.size;
		ray.y = (player.x - ray.x) * nTan + player.y;
		ray.xOffset = world.size;
		ray.yOffset =- ray.xOffset * nTan;
	}

	if (ray.angle == 0 || ray.angle == Math.PI) // Straight up or down
	{
		ray.x = player.x;
		ray.y = player.y;
		depthOfField = 8;
	}

	while (depthOfField < 8)
	{
		local mapX = ray.x / world.size;
		local mapY = ray.y / world.size;

		if (isDefined(map[mapX][mapY]) && map[mapX][mapY] == 1)
		{
			depthOfField = 8;
			ray.verticalX = ray.x;
			ray.verticalY = ray.y;
			ray.distanceV = getDistance(player.x, player.y, ray.x, ray.y);
		}				
		else
		{
			ray.x += ray.xOffset;
			ray.y += ray.yOffset;
			depthOfField++;
		}
	}
}

inline function getDistance(playerX, playerY, rayX, rayY)
{
	return Math.sqrt((playerX - rayX) * (playerX - rayX) + (playerY - rayY) * (playerY - rayY));
}

