                {
                    frameBuffersL[i][j] = 0.0;
                    frameBuffersR[i][j] = 0.0;
                }
            }

            timer.startTimer(30);
        }
        else
            timer.stopTimer();
    };

    Button1.setControlCallback(onButton1Control);
}

