inline function addStoragePanel(id, data)
{
	if (Content.componentExists(id))
		return Content.getComponent(id);

	local comp = Content.addPanel(id, 0, 0);
	comp.setValue(data);
	comp.set("visible", false);

	//	set "saveToPreset" delayed otherwise the
