const TableData = Table.registerAtParent(0);

inline function getIndex(x, y)
{
	//	all points in the table
	local points = TableData.getTablePointsAsArray();
	local index;

	//	compare the clicked/dragged points x & y values
	//	with all points and find the right one
	//	check what index this point has, and return it
	for (p in points)
		if (p[0] == x && p[1] == y)
			index = points.indexOf(p);

	return index;
}

inline function showPointInfo(x, y)
{
	//	you'll get the x & y values for clicked/dragged point (normalized)
	//	check which point is clicked/dragged
	local index = getIndex(x, y);

	return index + " | " + parseInt(x * 100)+"% | "+parseInt(y * 100) + "%";
};

