reg time = "";
reg Y = "";
reg M = "";
reg D = "";
reg date = "";
reg h = 0;
reg m = 0;
reg s = 0;
reg oldSec = 0;
const var months = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];


frame.setTimerCallback(function()
{
	time = Engine.getSystemTime(true);
	
	s = Math.round(time.charAt(17) != "0" ? time.substring(17,19) : time.substring(18,19));
	
	if (oldSec != s){
	    
        Y = time.substring(0,4);
        M = time.substring(5,7);
        D = time.substring(8,10);
	
        date = D + " " + months[Math.round(M)-1] + " " + Y;
	
        h = Math.round(time.charAt(11) != "0" ? time.substring(11,13) : time.substring(12,13));
        m = Math.round(time.charAt(14) != "0" ? time.substring(14,16) : time.substring(15,16));
	
	    Synth.addNoteOn(1, 90, 64, 0);
	    Synth.addNoteOff(1, 90, 200);
	    oldSec = s;
	      
	    this.repaint();
	}
});
frame.startTimer(30);



frame.setPaintRoutine(function(g)
{
	g.fillAll(Colours.darkgrey);
	
	g.setColour(Colours.withAlpha(Colours.black, 0.5));
	g.fillRoundedRectangle([160,140,180,30], 10);
	g.fillRoundedRectangle([200,320,100,30], 10);
	
	g.setColour(Colours.withAlpha(Colours.beige, 0.5));
	g.setFont("Arial", 30);
	g.drawAlignedText(date, [0,140,this.getWidth(),30], "centred");
	g.drawAlignedText(time.substring(11,16), [0,320,this.getWidth(),30], "centred");
	
	g.setColour(Colours.beige);
	
	for (i = 0; i < 12; i++){
	    
	    var hourIndexAngle = 2 * Math.PI / 12 * i - (Math.PI/2);
        var x = Math.cos(hourIndexAngle);
        var y = Math.sin(hourIndexAngle);
	    
	    g.drawLine(this.getWidth()/2 + x * 180, this.getWidth()/2 + x * 200, this.getHeight()/2 + y * 180, this.getHeight()/2 + y * 200, 6);
	}
	
	for (i = 0; i < 60; i++){
	    
	    var minIndexAngle = 2 * Math.PI / 60 * i - (Math.PI/2);
        var x = Math.cos(minIndexAngle);
        var y = Math.sin(minIndexAngle);
	    
	    g.drawLine(this.getWidth()/2 + x * 190, this.getWidth()/2 + x * 200, this.getHeight()/2 + y * 190, this.getHeight()/2 + y * 200, 3);
	}
	
	var secVector = getSecVector(s);
	g.drawLine(this.getWidth()/2, this.getWidth()/2 + secVector[0] * 185, this.getHeight()/2, this.getHeight()/2 + secVector[1] * 185, 1);
	
	var minVector = getMinVector(s);
	g.drawLine(this.getWidth()/2, this.getWidth()/2 + minVector[0] * 170, this.getHeight()/2, this.getHeight()/2 + minVector[1] * 170, 3);
	
	var hourVector = getHourVector(s);
	g.drawLine(this.getWidth()/2, this.getWidth()/2 + hourVector[0] * 100, this.getHeight()/2, this.getHeight()/2 + hourVector[1] * 100, 6);
    
	g.fillEllipse([240,240,20,20]);
	g.setColour(Colours.darkgrey);
	g.fillEllipse([245,245,10,10]);
});


inline function getSecVector(s)
{
    local secAngle = 2 * Math.PI / 60 * s - (Math.PI/2);
    local x = Math.cos(secAngle);
    local y = Math.sin(secAngle);
    return [x,y];
}

inline function getMinVector(s)
{
    local secAngle = 2 * Math.PI / 60 * m - (Math.PI/2);
    local x = Math.cos(secAngle);
    local y = Math.sin(secAngle);
    return [x,y];
}

inline function getHourVector(s)
{
    local secAngle = 2 * Math.PI / 12 * h - (Math.PI/2);
    local x = Math.cos(secAngle);
    local y = Math.sin(secAngle);
    return [x,y];
}

