inline function getPositionOfComponent(component)
{
	local pos = {"x": component.get("x"), "y": component.get("y")};

	local comp = component;

	//	check if component has parent and grandparents
	for (i = 0; comp.get("parentComponent") != ""; i++)
	{
		comp = getComponent(comp.get("parentComponent"));
		local p = getParentPosition(comp);
		pos.x += p.x;
		pos.y += p.y;
	}

	return pos;
};

//	get the parent position
inline function getParentPosition(parent)
{
	return {"x": parent.get("x"), "y": parent.get("y")};
};

//	get the component object
inline function getComponent(componentId)
{
	for (c in AllComponents)
		if (c.get("id") == componentId)
		{
			return c;
			break;
		}
}

