//! Functions
inline function: Colour getTextColour(baseColour: Colour, backgroundColour: Colour, shadeIndex: number)
{
	local bc = Colours.toHsl(backgroundColour);
	local c = Colours.toHsl(baseColour);

	c[0] = getShiftedHue(c[0], shadeIndex, 4);
	c[1] = getShiftedSaturation(shadeIndex, c[1], 0.5);
	c[2] = 1 - bc[2];

	return Colours.fromHsl(c);
}

inline function: Array generatePalette(baseColour: Colour)
{
	local result = [];

	for (i = 0; i < 10; i++)
	{
		local c = Colours.toHsl(baseColour);

		c[0] = getShiftedHue(c[0], i / 10, 4);
		c[1] = getShiftedSaturation(i / 10, c[1], 0.5);
		c[2] = (i + 1) / 10;

		result.push(Colours.fromHsl(c));
	}

	return result;
}

inline function: number getShiftedHue(baseHue: number, index: number, maxShift: number)
{
	return baseHue + maxShift * index / 360;
}

inline function: number getShiftedSaturation(index: number, maxSaturation: number, steepness: number)
{
    local x = index;    
    local a = maxSaturation * steepness;
    local b = maxSaturation;
    local saturation = -4 * a * Math.pow((x - 0.5), 2) + b;

    return Math.max(0.0, Math.min(1.0, saturation));
}

