inline function createPreset(panelName, parent, column, row, preset) {
		local qsW = 120;
		local qsH = 25;
		local margin = 5;

		local qsX = margin + column * (qsW + margin);
		local qsY = margin + row * (qsH + margin);
		local qsBg = 0x11FFFFFF;

		local qsPanel = Content.addPanel("qs" + panelName, 10+qsX, 10+qsY);

		Content.setPropertiesFromJSON("qs" + panelName, {
			"parentComponent": parent,
			"text": preset,
			"width": qsW,
			"height": qsH,
			"allowCallbacks": "All Callbacks",
			"bgColour": qsBg
		});

		qsPanel.setPaintRoutine(function(g) {
			var ar = this.getLocalBounds(0);
			g.setColour(this.get("bgColour"));
			g.fillRoundedRectangle(ar, 4);
			g.drawAlignedText(this.getId().replace("qs",""), ar, "centred");
		});


		qsPanel.setMouseCallback(function(event) {
			var pr = this.get("text"); 
			if (event.clicked) {
				for (var i = 0; i < pr.length; i++) {
					var component = Content.getComponent(pr[i][0]);

					component.setValue(pr[i][1]);
					component.changed();
				}
			}

			if (event.hover) {
				this.set("bgColour", 0x33FFFFFF);
				this.repaint();
			} else {
				this.set("bgColour", 0x11FFFFFF);
				this.repaint();
			}

			if (event.hover && Content.isMouseDown()) {
				this.set("bgColour", 0x66BBBBFF);
				this.repaint();
			}
		});

		return qsPanel;
	}

