inline function escapeString(str) {
    local obj = {};
    obj.s = str;

    return trace(obj.s); // let HISE do the escaping for us
}

inline function deescapeString(str) {
    // De-escape double quotes
    while(str.contains('\\"')) {
        str = str.replace('\\"', '"');
    }
    
    // De-escape newlines
    while(str.contains('\\n')) {
        str = str.replace('\\n', '\n');
    }
    
    return str;
}

