    var centerX = a[2] / 2;
    var fillWidth;
    var startX = 12;

    if (isBidirectional)
    {
        if (obj.valueNormalized > 0.5)
        {
            startX = centerX;
            fillWidth = ((a[2] - 12) * obj.valueNormalized) - centerX;
        }
        else
        {
            fillWidth = centerX * (1.0 - obj.valueNormalized * 2);
            startX = centerX - fillWidth;

            fillWidth = Math.min(fillWidth, centerX - 12);
            startX = Math.max(startX, 12);
        }
        g.fillRoundedRectangle([startX, a[3] / 2 - 3 / 2, fillWidth, 3], 2);
    }
    else
    {
        fillWidth = (a[2] - 24) * obj.valueNormalized;
        g.fillRoundedRectangle([12, a[3] / 2 - 3 / 2, fillWidth, 3], 2);
    }

    var w = a[2] * 0.2;
    var x = a[2] * obj.valueNormalized - (w + 4) * obj.valueNormalized + 2;

    g.setColour(Colours.grey);
    g.fillRoundedRectangle([x + 1, a[3] / 2 - (a[3] - 4) / 2, w - 2, a[3] - 4], 8);
