Panel1.setPaintRoutine(function(g)
{
	var a = this.getLocalBounds(0);
	var start = -Math.PI/4.0;
	var arc = 3.0 * Math.PI / 2.0;
	var step = arc / (labels.length-1);
	var reversePoint = Math.floor(labels.length / 2.0);

	g.rotate(start, [a[2] / 2, a[3] / 2]);

	for (i = 0; i < labels.length; i++)
	{
		g.setColour((this.data.v == i ) ? Colours.red : Colours.white);

		if (i < reversePoint)
		{
			g.drawAlignedText(labels[i], a, "left");
			g.rotate(step, [a[2] / 2, a[3] / 2]);
			continue;
		}

		if (i == reversePoint)
			g.rotate(Math.PI, [a[2] / 2, a[3] / 2]);

		g.drawAlignedText(labels[i], a, "right");
		g.rotate(step, [a[2] / 2, a[3] / 2]);
	}
});




