			g.rotate(step, [a[0] + a[2] / 2, a[3] / 2]);
			continue;
		}

		if (i == reversePoint)
			g.rotate(Math.PI, [a[0] + a[2] / 2, a[3] / 2]);

		g.drawAlignedText(labels[i], [a[0] + someIdentation, a[1], a[2], a[3]], "left");
		g.rotate(step, [a[0] + a[2] / 2, a[3] / 2]);
	}
});


inline function conformToSquare(a)
{
	a[0] = (a[2] - a[3]) / 2;
	a[2] = a[3];

	return a;
}


