namespace Animate
{
	inline function increase(property, end, step)
	{
		this.set(property, this.get(property) + step);

		if (this.get(property) >= end)
			this.stopTimer();
	}

	inline function decrease(property, end, step)
	{
		this.set(property, this.get(property) - step);

		if (this.get(property) <= end)
			this.stopTimer();
	}
}

