function positionPanels()
{
	// go through the array FXPanels putting everyone in their right place
	for (i = 0; i< FXPanels.length; i++)
	{
		FXPanels[i].setPosition(0, FXPanelHeight* i, FXPanelWidth, FXPanelHeight);
	}
}

function reorderPanels(panel, newPos)
{
	reg existingPos = FXPanels.indexOf(panel);
	if(existingPos != newPos)
	{
		reg tempPanel = FXPanels[newPos];
		FXPanels[newPos] = panel;
		FXPanels[existingPos] = tempPanel;
	}
	positionPanels();
}

