//	MCB	------------------------------------------------------------
const FXPnlsMCB = function(event)
{
	var h = MainPanel.getHeight();
	var order = MainPanel.getValue();

	var slot = h / FXPnls.length;
	var idx = FXPnls.indexOf(this);

	if (event.clicked || event.drag)
	{
		if (event.clicked)
		{
			for (i = 0; i < FXPnls.length; i++)
				order[i] = Math.round(FXPnls[i].get("y") / slot);

			this.data.startpos = order[idx];

			//	just for the look
			this.set("textColour", Colours.withAlpha(Colours.white, 0.7));
		}

		if (event.drag)
		{
			this.data.pos = Math.round(this.get("y") / slot);

			if (this.data.pos != this.data.startpos)
			{
				var swapidx = order.indexOf(this.data.pos);

				FXPnls[swapidx].set("y", slot * this.data.startpos);

				//	swap places
				order[idx] = this.data.pos;
				order[swapidx] = this.data.startpos;

				//	change start position
				this.data.startpos = this.data.pos;
			}
		}
	}

	if (event.mouseUp)
	{
		this.set("y", slot * this.data.pos);
		this.set("textColour", Colours.withAlpha(Colours.white, 0.2));
		Console.print("release: "+ this.data.pos);
	}
};

for (p in FXPnls)
	p.setMouseCallback(FXPnlsMCB);

