        PresetList.set("items", presetNames.join("\n"));
    }
    
    inline function onPresetListControl(component, value) {
        local items = component.get("items").split("\n");
        local preset = PresetHandler.loadPresetFile(items[value]);
        setControlValues(preset);
    };
    
    inline function onShowPresetFolderControl(component, value) {
        if (value) PresetHandler.showPresetFolder();
    };
    
    inline function onSavePresetControl(component, value) {
        SavePresetOptions.showControl(value);
    };
    
    inline function onSaveOkControl(component, value) {
        if (value) {
            local presetName = PresetNameToSave.get("text");
            PresetHandler.savePresetFile(presetName, getControlValues());
            SavePreset.setValue(false);
            SavePreset.changed();
            populatePresetList();
        }
    };
    
    inline function onSaveCancelControl(component, value) {
        SavePreset.setValue(false);
        SavePreset.changed();
    };
    
    inline function getControlValues() {
        return {
            "SlickSlider": SlickSlider.getValue(),
            "BeautifulButton": BeautifulButton.getValue()
        };
    }
    
    inline function setControlValues(data) {
        SlickSlider.setValue(data.SlickSlider);
        BeautifulButton.setValue(data.BeautifulButton);
    }
}

// Provides functions for loading and saving preset files from the file system
namespace PresetHandler {
    inline function getPresetFolder() {
        return FileSystem.getFolder(FileSystem.UserPresets);
    }

	inline function fetchPresetNames() {
		local presets = FileSystem.findFiles(getPresetFolder(), "*.preset", true);
		local presetNames = [];
		for (file in presets)
			presetNames.push(file.toString(1));

		return presetNames;
	}

	inline function loadPresetFile(presetName) {
		local presetFile = FileSystem.findFiles(getPresetFolder(), presetName + ".preset", true);
		return presetFile[0].loadAsObject();
	}

	inline function savePresetFile(presetName, data) {
		local presetFile = getPresetFolder().getChildFile(presetName + ".preset");
		presetFile.writeObject(data);
	}

	inline function presetNameExists(presetName) {
		return getPresetFolder().getChildFile(presetName + ".preset").isFile();
	}

	inline function showPresetFolder() {
		getPresetFolder().show();
	}
}

