var area = 0;
var closest = 400;
var tempAngle = 0;
var dropAngle = 0;
var curr = 400;
var slice = 0;

//  Mouse Callback  ------------------------------------------
MultiPad.setMouseCallback(function(event)
{
    var anglesTrue = [162, 234, 306, 18, 90];
    
    var w = this.getWidth();
    var h = this.getHeight();
    var v = this.data.value;

	if(event.clicked || event.drag && !event.shiftDown && !event.altDown)
    {
        v.x = event.x;
        v.y = event.y;
        
        v.xVal = Math.range(event.x / (w * 0.5) - 1, -1, 1) ;
        v.yVal = Math.range(2 - event.y / (h * 0.5) - 1, -1, 1);
        
        //  Calculate the radius    -----------------------------
        v.rad = Math.sqrt(Math.sqr(v.xVal) + Math.sqr(v.yVal));
        v.rad = Math.range(v.rad, 0, 1);
        
    //  length between marker and areas
        v.x0 = w/2 + w/2 * v.rad * Math.cos(Math.PI*0.4);   //Bassoon
        v.y0 = h/2 + w/2 * v.rad * Math.sin(Math.PI*0.4);
	
        v.x1 = w/2 + w/2 * v.rad * Math.cos(Math.PI*0.8);   //Bandoneon
        v.y1 = h/2 + w/2 * v.rad * Math.sin(Math.PI*0.8);
	
        v.x2 = w/2 + w/2 * v.rad * Math.cos(Math.PI*1.2);   //Master
        v.y2 = h/2 + w/2 * v.rad * Math.sin(Math.PI*1.2);
	
        v.x3 = w/2 + w/2 * v.rad * Math.cos(Math.PI*1.6);   //Violin
        v.y3 = h/2 + w/2 * v.rad * Math.sin(Math.PI*1.6);
	
        v.x4 = w/2 + w/2 * v.rad * Math.cos(Math.PI*2.0);   //Clarinet
        v.y4 = h/2 + w/2 * v.rad * Math.sin(Math.PI*2.0);
        
        v.length[0] = Math.sqrt(Math.sqr(v.x0 - v.x) + Math.sqr(v.y0 - v.y));
        v.length[1] = Math.sqrt(Math.sqr(v.x1 - v.x) + Math.sqr(v.y1 - v.y));
        v.length[2] = Math.sqrt(Math.sqr(v.x2 - v.x) + Math.sqr(v.y2 - v.y));
        v.length[3] = Math.sqrt(Math.sqr(v.x3 - v.x) + Math.sqr(v.y3 - v.y));
        v.length[4] = Math.sqrt(Math.sqr(v.x4 - v.x) + Math.sqr(v.y4 - v.y));
        
        //  Calculate values depended on distance between Marker and the 5 areas
        for(i=0; i<5; i++)
        {
            if(v.length[i] < v.marker)
            {
                v.values[i] = 1 - v.length[i] * (1 / (v.marker));
                //areas[v.order[i]].setValue(v.values[i]);
                areas[i].setValue(v.values[v.order[i]]);
            }
            else
            {
                v.values[i] = 0;
                //areas[v.order[i]].setValue(0);
                areas[i].setValue(v.values[v.order[i]]);
            }
        }
    }
    
    if(event.clicked && event.shiftDown)
    {
        //  Calculate closest area from marker (when clicked)
        for(i=0; i<5; i++)
        {
            if(v.length[i] < closest)
            {
                closest = v.length[i];
                area = i;
                slice = v.order[area];
                Console.print("area:"+area+" slice:"+slice);
            }
        }
        tempAngle = anglesTrue[v.order[slice]];
        //Console.print("tempAngle:"+tempAngle);

    }
    if(event.shiftDown && event.drag)
    {
        dropAngle = tempAngle + (event.dragX - event.dragY);
        if(dropAngle < 0)
           {
               dropAngle = dropAngle + 360;
           }
           if(dropAngle > 360)
           {
               dropAngle = dropAngle -360;
           }
        v.angles[v.order[slice]] = dropAngle;
        //Console.print("dropAngle:"+dropAngle);
    }
        
    if(event.shiftDown && event.mouseUp && dropAngle > 0)
        {
            var dropArea = 9;
            if(dropAngle > 126 && dropAngle < 198)
            {
                dropArea = 0;
            }
            if(dropAngle > 198 && dropAngle < 270)
            {
                dropArea = 1;
            }
            if(dropAngle > 270 && dropAngle < 342)
            {
                dropArea = 2;
            }
            if(dropAngle > 342 || dropAngle < 54)
            {
                dropArea = 3;
            }
            if(dropAngle > 54 && dropAngle < 126)
            {
                dropArea = 4;
            }
            
            // test
            var temp1 = v.order.indexOf(area);
            var temp2 = v.order.indexOf(dropArea);
            v.order[temp1] = dropArea;
            v.order[temp2] = area;

            
            for(i=0; i<5; i++)
            {
                v.angles[i] = anglesTrue[i];
                this.repaint();
                Console.print("order:"+v.order[i]);
            }
            //Console.print("dropAngle:"+dropAngle);
            //Console.print("dropArea:"+dropArea);
            closest = 400;
            dropAngle = 0;  //  reset dropAngle

        }
    
    
    //  Scale marker size   =========================================
    if(event.altDown && event.drag)
    {
        v.marker = v.marker + (event.dragX - event.dragY) * 0.1;
        v.marker = Math.range(v.marker, 40, 160);
        this.repaint();
    }
    
    this.setValue(v);
    this.repaint();
    this.changed();

});

