        Q = ((8 - 0.1) / Math.log10(200)) * (Math.log10(200) - (Math.log10(y + 100)));
                       
        Q = Math.range(Q, 0.1, 8);
        
        this.data.lastY = y; //Store y value
        
        // Set EQ
        ParametriqEQ1.setAttribute(2, Q);
        
        // Display the rounded Q value
        Qlabel = Engine.doubleToString(Q, 1);
        Label1.set("text", "Q: " + Qlabel);
    }
    
    
    // On release, stores the panel position and display no text
    if (event.mouseUp){
        posX = Panel1.getGlobalPositionX();
        posY = Panel1.getGlobalPositionY();
        Label1.set("text", "");
    }

});

